/**
 * Next.js instrumentation hook — runs once when the server starts.
 * Used to launch the Signal adapter as a persistent background process.
 *
 * Requires next.config: experimental.instrumentationHook = true
 */

export async function register() {
  // Only run in the Node.js runtime (not edge/browser)
  if (process.env.NEXT_RUNTIME !== 'nodejs') return;

  // Only start if Signal is explicitly enabled
  if (process.env.SIGNAL_ENABLED !== 'true') return;

  // Defer slightly so the Next.js server is fully initialised first
  setTimeout(() => startSignalAdapter(), 2000);
}

async function startSignalAdapter(): Promise<void> {
  try {
    const { loadSignalConfig } = await import('./lib/signal/config');
    const { SignalAdapter } = await import('./lib/signal/adapter');
    const { SignalRouter } = await import('./lib/signal/router');

    const config = loadSignalConfig();

    if (!config.phoneNumber) {
      console.warn('[Signal] SIGNAL_PHONE_NUMBER not set — adapter disabled');
      return;
    }

    if (!config.socketPath && !(config.tcpHost && config.tcpPort)) {
      console.warn(
        '[Signal] No connection configured — set SIGNAL_SOCKET_PATH or ' +
          'SIGNAL_TCP_HOST + SIGNAL_TCP_PORT'
      );
      return;
    }

    if (config.allowedNumbers.length === 0) {
      console.warn('[Signal] SIGNAL_ALLOWED_NUMBERS is empty — no one can reach the adapter');
    }

    console.log(
      `[Signal] Starting adapter for ${config.phoneNumber} ` +
        `(${config.allowedNumbers.length} allowed numbers)`
    );

    const adapter = new SignalAdapter(config);
    // Router wires up the 'message' event listener
    new SignalRouter(adapter, config);

    await adapter.connect();
    console.log('[Signal] Adapter ready');
  } catch (err) {
    // Log but do not crash the Forge server
    console.error('[Signal] Adapter failed to start:', err);
  }
}

