/** @type {import('next').NextConfig} */
const nextConfig = {
  experimental: {
    instrumentationHook: true,
  },
  webpack: (config, { isServer }) => {
    if (isServer) {
      // Externalize Node.js built-in modules for server-side only
      config.externals = [
        ...(config.externals || []),
        'crypto',
        'net',
        'fs',
        'fs/promises',
        'path',
        'stream',
        'dns',
        'events',
        'pg',
        'pgpass',
        'split2',
      ];
    }
    return config;
  },
};

module.exports = nextConfig;

